auth_ins AS (
  INSERT INTO auth.users (id, instance_id, email, encrypted_password, email_confirmed_at, aud, role, created_at, updated_at, raw_app_meta_data, raw_user_meta_data)
  SELECT id, '00000000-0000-0000-0000-000000000000'::uuid,
         'seed+' || code || '@eveandeden.demo',
         crypt('seed-no-login', gen_salt('bf')), now(),
         'authenticated','authenticated', now(), now(),
         '{"provider":"email","providers":["email"]}'::jsonb, '{}'::jsonb
  FROM src
  ON CONFLICT (id) DO NOTHING
  RETURNING id
),
prof_ins AS (
  INSERT INTO public.profiles (id, user_type, full_name, phone, country, language, is_active)
  SELECT id, 'provider', full_name, phone, 'MA', 'fr', true FROM src
  ON CONFLICT (id) DO NOTHING
  RETURNING id
)
INSERT INTO public.providers (user_id, full_name, specialty, city, country, bio, languages, is_verified, accepting_patients, clinic_address, review_status)
SELECT id, full_name, specialty, city, 'MA', bio, ARRAY['fr','ar']::text[], true, true, addr, 'verified'
FROM src
WHERE NOT EXISTS (SELECT 1 FROM public.providers p WHERE p.user_id = src.id);